reg [1:0] ledi;
   always @ (posedge clockbuf)
     begin
        case(count[5:0])
          0: ledi <= 2'b00;
          1: ledi <= 2'b11;
          2: ledi <= 2'b01;
          3: ledi <= 2'b10;
          4: ledi <= 2'b00;
          5: ledi <= 2'b11;
          6: ledi <= 2'b00;

          default: ledi <= 2'b11;
        endcase
     end

   SB_IO #(.PIN_TYPE(6'b110000), .IO_STANDARD("SB_LVCMOS")) led_ddr
     (.PACKAGE_PIN(led),
      .CLOCK_ENABLE(1'b1),
      .OUTPUT_CLK(clockbuf),
      .OUTPUT_ENABLE(1'b1),
      .D_OUT_0(ledi[0]), // data out to pin                                                                                              
      .D_OUT_1(ledi[1]));
